function useInView(ref: React.RefObject<HTMLDivElement | null>): boolean {
  const [inView, setInView] = useState<boolean>(false);
  useEffect(() => {
    const obs = new IntersectionObserver(
      ([e]) => { if (e.isIntersecting) setInView(true); },
      { threshold: 0.15 }
    );
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, [ref]);
  return inView;
}

interface SectionProps {
  id: string;
  children: ReactNode;
  style?: CSSProperties;
}

function Section({ id, children, style }: SectionProps) {
  return (
    <section id={id} style={{ padding: "100px 0", ...style }}>
      {children}
    </section>
  );
}

interface FadeInProps {
  children: ReactNode;
  delay?: number;
  style?: CSSProperties;
}

function FadeIn({ children, delay = 0, style }: FadeInProps) {
  const ref = useRef<HTMLDivElement>(null);
  const inView = useInView(ref);
  return (
    <div
      ref={ref}
      style={{
        opacity: inView ? 1 : 0,
        transform: inView ? "translateY(0)" : "translateY(32px)",
        transition: `opacity 0.7s ease ${delay}s, transform 0.7s ease ${delay}s`,
        ...style,
      }}
    >
      {children}
    </div>
  );
}

